INSERT INTO dms_document_types (code, document_name, document_description, tier, rlmu, discipline_code, discipline_name, acceptable_status, is_active, display_order)
VALUES
('0480', 'Other Agreement', 'Other Agreement', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI., AFU, AFP, AFT', true, 1),
('0706', 'Independent Assessment Report', 'External review and assessment of project health that usually includes benchmarking and recommendations from other companies implementing similar work or projects.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 2),
('0709', 'Risk Assessment Report', 'Overall assessment of overall compound technical risk foreseen for the project.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 3),
('0712', 'Community Engagement', 'Community Affairs, local content issues, societal effects of project, local business development, etc.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 4),
('0780', 'Other Assessment Report', 'Health check, GAP analysis etc.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 5),
('1905', 'Benchmarking Data', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 6),
('3004', 'Equipment Criticality Rating Report', 'Shows criticality rating of equipment, sparing, maintenance testing and inspection requirements, spare parts requirements etc.  Will feed into maintenance reference plan.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 7),
('3180', 'Other Estimate', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 8),
('3311', 'Change Notification', 'An advance notice to another party, e.g. another design department or fabrication facility, that there is going to be a change to a document that has been issued for construction. Synonyms include DCN Design Change Notice, ACN Advanced Change Notice.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 9),
('3322', 'Demonstration Note On Compliance', 'A document that demonstrates that the design meets the Process Safety Basic Requirements (PSBR) of DEM 2 with evidences and references to documents.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 10),
('3341', 'Manpower Histogram', 'Histograms to show current and predicted manpower through project broken down by trade/profession', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 11),
('3347', 'Minutes Of Meeting', 'Minutes of meetings between client and contractor as requested in contract procedures', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 12),
('3352', 'Organogram', 'Represents an organisation of people, indicating roles and reporting lines in a tree-like structure. May include the names of individuals. Associated with AA only.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 13),
('3366', 'Technical Query', 'Technical Query  Includes STQ (Site Technical Query)', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 14),
('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.   Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'HX', 'HSE&S General', 'ASB, AFC, AFU, AFD', true, 15),
('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.   Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'MX', 'Mechanical Other', 'ASB, AFC, AFU, AFD', true, 16),
('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.   Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 17),
('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.  Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'AA', 'Management & Project Eng', 'ASB, AFC, AFU, AFD', true, 18),
('4301', 'Action List', 'Includes Punch List.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 19),
('4303', 'Applicable Standards List', 'Provides the lists of Company Standards identified for use as baseline standards for a project.  It also provides:  - The list of International, National and Industry Codes and Standards that are referenced in the Company Standards and project specific Specifications.  - The list of Codes (e.g. process unit codes) to be used by the project. ', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 20),
('4322', 'Equipment Summary List', 'An extract from a Register (see 6612 Equipment Register) that is used as a secondary reference (ie. not the master).', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 21),
('4880', 'Other Manual', 'A document that describes methods of working to be used to accomplish an activity. Synonym: Guide, Guideline. Warning: Not to replace "Books", as defined in the EIS Section 3.4 which requires an Index to be created. See Index of Documents.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 22),
('5206', 'Other Picture', 'Photo or Illustration', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 23),
('5529', 'Project Philosophy', 'Including buildings, access, drainage, corrosion/materials, electrical design, fire and gas, commissioning, isolation, maintenance, operations (inc. start-up/shutdown), earthing, HVAC, metering, process control, well control,  utility requirements and design.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 24),
('5706', 'Assurance Plan', 'Quality, compliance, technical, value, cost and schedule assurance.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 25),
('5726', 'Field Development Plan', 'Synonyms: Master Development Plan, Area Development Plan, Base Development Plan.  Sub-surface, surface, reservoir management , joint venture partners, high level operations philosophy, high level facilities description, environmental impact, HSE and QA/QC principles, Venture setup aspects, well engineering, production technology.  From OPMG: The plan provides an evaluation of field development alternatives together with the selection of an optimal development concept based on subsurface scenarios (uncertainty) and field engineering options.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 26),
('5753', 'Permit Plan', 'Permits and licenses required to allow project work and construction to take place', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 27),
('5759', 'Project Control Plan', 'Throughout the project phases, but in particular during the implementation phase, the project control systems and procedures should be documented in the Project Control Plan PCP, which will become part of the overall Project Procedures Manual. The PCP may be published as part of the Project Execution Plan (AA5798).', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 28),
('5760', 'Project Execution Plan', 'One of the most important documents on a project, established prior to FEED. The will largely decide the project organisational requirements and lay the groundwork for detailed project planning and cost estimating. The PEP may be as short or as long as warranted by the size and complexity of the project but it is a required deliverable. Its main value is in inspiring and recording the strategic thinking process and acting as a blueprint for project staff as the project moves forward. Project Execution Strategy documents (PES) are also classified here.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 29),
('5768', 'Risk and Opportunity Management Plan', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 30),
('5775', 'Stakeholder Engagement Plan', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 31),
('5778', 'Sustainable Development Plan', 'Community Affairs, local content issues, societal effects of project, local business development, etc.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 32),
('5787', 'Verification Scheme', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 33),
('5798', 'Project Plan', 'Reserved for project wide Discipline Management Plans such as Project QA Plan, Project HSES Plan, Project IM Plan, etc... For Discipline AA only, this doc type is used to classify Project Implementation Plan (PIP) and Project Execution Plan (PEP).', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 34),
('5800', 'Interface Plan', 'Interface between internal and external parties (esp. between contract scopes). May be treated as a BOOK (see Index of Documents) and contain Interface Procedures and Interface Agreements as separate documents.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 35),
('5880', 'Other Plan', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 36),
('6006', 'Safety Instruction Permit', 'Safety Instruction / Permit to Work, Certificate of Fitness for Purpose', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 37),
('6011', 'Authority / License', 'Governmental or 3rd party authority or license', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 38),
('6080', 'Other Procedure', 'For Project Procedures Manual use AA5798, unless project wishes to register separate documents for individual procedures within a Project Procedures Manual.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 39),
('6612', 'Equipment Register', 'A register/database containing all pertinent data about equipment that is installed on the facility. Frequently referred to as the CMMS (Computerised Maintenance Management System). Refer to the EPC/IM Contract Scope of Work (the EXHIBIT-G, section 5.3 / 5.4 / 5.5 for more detail). Includes Equipment Database, Summary Equipment Database, Approved Equipment List etc.  For Project Material Master data list use doc type 6680.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 40),
('6680', 'Other Register', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 41),
('7001', 'Audit Report', 'An authoritative evaluation of the quality, performance, system(s) or processes of a given body in a given discipline. Usually done by a qualified auditor.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 42),
('7080', 'Other Report', 'Including: Summary Report, Final Report, Assessment Report, Evaluation Report, Commissioning Report, Completion Report, Asset Report, Performance Report.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 43),
('7406', 'Value Assurance Review Report', 'Assessment report of the project team, their work and the deliverables so far to reach a gate decision. The VAR is a mandatory cross-functional review of the project, involving all relevant disciplines. It covers the full scope of the project and assesses the maturity of the development and especially the feasibility of the proposed concept and plan. Includes any Independent Peer Review Report.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 44),
('7416', 'Other Assurance Review Report', 'Provides an independent assurance that project schedules, cost estimates, technical design, competence, etc. accurately represent the project scope, the risks to project delivery, and are compliant with Group project guides and standards. Usually used as input to a Value Assurance Review VAR. Includes Estimate and Schedule Assurance Review (ESAR) under FA, and Technical Assurance Reviews under AA for multidiscipline reviews, or individual disciplines for specific reviews.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 45),
('7480', 'Other Review Report', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 46),
('7739', 'Project Specification', 'A technical description of the information on a Project necessary to prepare a +/-10% estimate, including references to:  - technical specifications required to prepare detailed design and engineering work  - procedures and requirements for the execution of the work and services for the realisation of a project Note: This doc type is not a BOOK as defined in the EIS. It is a document referencing other specifications, procedures, etc.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 47),
('7753', 'Terms Of Reference', 'Specifies the scope and details of the activity to which it refers and any conditions relating to the appointment of a person(s) to undertake the activity (usually used in relation to the supply of professional services). It recalls the background and specifies the scope of the evaluation, states the main motives for an evaluation and the questions asked. It sums up available knowledge and outlines an evaluation method and describes the distribution of work, schedule and the responsibilities among the people participating in an evaluation process.', NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 48),
('8280', 'Other Schedule', NULL, NULL, NULL, 'AA', 'Management & Project Eng', 'IFI, AFU, AFP, AFT', true, 49),
