('4027', 'Schematic Diagram', 'A diagram used to show the high-level power supply and distribution to and between major electrical equipment. It identifies bus bars, cable and transformer sizes. It provides voltage and short circuit levels._x000D_ Single Line Diagrams (SLD), Utility Flow Diagrams (UFD), Three Line Diagrams (TLD), Protective Device Coordination Diagrams (PDCD). Includes SLDs for Electrical Substations.', 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 117),
('4030', 'Wiring Diagram', 'Shows the connections of an installation or its component devices or parts. It may cover internal or external connections or both, and contains such detail as is needed to make or trace connections that are involved.  Includes: Wiring Diagram, Cable Block Diagram, Cable Interconnection Diagram, Cable Schedule, Block Diagram, Electrical Wiring Interconnection Drawing, Panel / Kiosk Internal Wiring Drawing.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 118),
('4033', 'Routing Drawing', 'Cable tray / duct / trench routing and support arrangement drawing.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 119),
('4036', 'Classification Drawing', 'Hazardous Area Classification Drawing showing the location and extent of each classified area, inclusive of Area Classification schedules. Includes Zone Plans.', 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 120),
('4039', 'Lighting Layout Drawing', 'Shows the positions, circuitry and details of lighting (general, emergency, navigational, etc.) and small power (socket outlets) in an area.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 121),
('4042', 'Earthing Drawing', 'Earthing/Grounding drawings show the earth/ground protection system for the facility, including location and route of earth conductors and earth electrodes.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 122),
('4080', 'Other Drawing', NULL, 'Tier 1', 'RLMU', 'EA', 'Electrical', 'ASB, AFC, AFU, AFD', true, 123),
('4301', 'Action List', 'Includes Punch List.', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 124),
('4309', 'Cable Schedule', 'A schedule / list of cables, usually identified by a unique cable number plus details (type, cores, rating, routing etc).', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 125),
('4312', 'Consumer Load List', 'A listing of each significant consumer/load item with key power supply information. It includes voltage, starting and running current, protection device ratings. It may include characteristics of the power system. A Load List feeds directly into a system Load Flow Study.', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 126),
('4380', 'Other List', NULL, NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 127),
('4880', 'Other Manual', 'A document that describes methods of working to be used to accomplish an activity. Synonym: Guide, Guideline. Warning: Not to replace "Books", as defined in the EIS Section 3.4 which requires an Index to be created. See Index of Documents.', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 128),
('5180', 'Other Design', NULL, NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 129),
('5529', 'Project Philosophy', 'Including buildings, access, drainage, corrosion/materials, electrical design, fire and gas, commissioning, isolation, maintenance, operations (inc. start-up/shutdown), earthing, HVAC, metering, process control, well control,  utility requirements and design.', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 130),
('5798', 'Project Plan', 'Reserved for project wide Discipline Management Plans such as Project QA Plan, Project HSES Plan, Project IM Plan, etc... For Discipline AA only, this doc type is used to classify Project Implementation Plan (PIP) and Project Execution Plan (PEP).', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 131),
