('7080', 'Other Report', 'Including: Summary Report, Final Report, Assessment Report, Evaluation Report, Commissioning Report, Completion Report, Asset Report, Performance Report.', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 135),
('7416', 'Other Assurance Review Report', 'Provides an independent assurance that project schedules, cost estimates, technical design, competence, etc. accurately represent the project scope, the risks to project delivery, and are compliant with Group project guides and standards. Usually used as input to a Value Assurance Review VAR. Includes Estimate and Schedule Assurance Review (ESAR) under FA, and Technical Assurance Reviews under AA for multidiscipline reviews, or individual disciplines for specific reviews.', NULL, NULL, 'EA', 'Electrical', 'IFI, AFU, AFP, AFT', true, 136),
