('8203', 'HAZOP / HAZID', 'The objective of a HAZOP study is to identify safety hazards and operability issues of a facility design or a process. Uses a creative, systematic approach to examine the design.  This item includes both HAZID and HAZOP studies.', NULL, NULL, 'HA', 'HSE&S', 'IFI, AFU, AFP, AFT', true, 188),
('8206', 'Environmental Impact Assessment', 'A report on the results of a study of the environmental impacts attributable to the project, used as a basis of decision-making, and which includes a description of proposed measures to mitigate the impacts.', NULL, NULL, 'HA', 'HSE&S', 'IFI, AFU, AFP, AFT', true, 189),
('8209', 'Fire Risk Assessment', 'Fire and Explosion Hazard Analysis (FEHA), Fire Hazard Assessment (FHA), Fire and Blast Assessment (FBA).', NULL, NULL, 'HA', 'HSE&S', 'IFI, AFU, AFP, AFT', true, 190),
('8212', 'Quantitative Risk Assessment', 'Quantitative Risk Assessment. Also Concept Risk Assessment (CRA) and Concept Safety Assessment (CSA). Note: For use in HSE&S discipline only', NULL, NULL, 'HA', 'HSE&S', 'IFI, AFU, AFP, AFT', true, 191),
('8215', 'Safety Case', 'A document produced by the operator describing the SMS. This requires the formal identification of the hazards and risks; the measures taken to reduce the identified risks to a level that is As Low As Reasonably Practicable; and the Safety Management System to ensure the implementation and compliance of risk reduction measures.', NULL, NULL, 'HA', 'HSE&S', 'IFI, AFU, AFP, AFT', true, 192),
