('3322', 'Demonstration Note On Compliance', 'A document that demonstrates that the design meets the Process Safety Basic Requirements (PSBR) of DEM 2 with evidences and references to documents.', NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 220),
('3366', 'Technical Query', 'Technical Query  Includes STQ (Site Technical Query)', NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 221),
('4045', 'Block Diagram', 'A simplified representation of a control system(s) showing the main connections between the field signals and the control system devices. Usually includes a high-level summary of the control system hardware, such as the types and quantity of controllers and I/O items.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 222),
('4048', 'Cause and Effect Diagram', 'A chart or matrix with logic representation of the relationship between a field condition (cause) and the results of that condition (effects) within a control system. It links measurements, alarms, trips and corresponding actions.  Does not include Fishbone cause and effect (a.k.a. Ishikawa Diagram) used for Root Cause Analysis or HAZOP study techniques. Includes Process Safety Logic Charts (PSLC).', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 223),
('4051', 'Instrument Hook-Up Drawing', 'A drawing showing the details of a typical installation of a group of instruments or a single instrument. These are typically arranged in a book or manual.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 224),
('4054', 'Instrument Location Drawing', 'A 2D plan view of a process area showing the location and identification of instruments, including junction boxes, marshalling cabinets, control rooms and equipment rooms.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 225),
('4057', 'Instrument Loop Drawing', 'A diagram showing a control loop (or multiple loops) including connections, signal types and ranges, cables, junction boxes, terminations and configuration of the instruments and devices within each loop.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 226),
('4060', 'Instrument Panel Layout Drawing', 'A drawing of an instrument panel, cubicle, rack and/or console. Layout and orientation of the items installed on the panel. It includes the panel assembly and details. Includes instrument and junction box panel, cabinet and rack layouts.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 227),
('4063', 'Logic Diagram', 'A diagram showing the sequence of logic operations to be performed by a safety system or a sequential control system. It includes alarm system logic.  For process safety logic charts (PSLC) use doc type 4048 Cause and Effect.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 228),
('4066', 'Control System Architecture Drawing', 'High-level drawing showing the main components and the configuration of the control system in a facility/project: PLC, DCS, SCADA, Communication, ESD, PSD, FGS, etc. It shows device counts, networks, protocols, hardware/servers, workstations, etc.', 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 229),
('4080', 'Other Drawing', NULL, 'Tier 1', 'RLMU', 'IN', 'Instrumentation', 'ASB, AFC, AFU, AFD', true, 230),
('4301', 'Action List', 'Includes Punch List.', NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 231),
('4318', 'Instrument Index', 'List of all instruments (tags) with key Instrument identification, including PandID tag numbers, description, service, types, locations, classified area, connected system, etc.', NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 232),
('4321', 'Instrument Summary List', 'List with instrument summary information. A summary of and/or a complement to the Instrument Index. Includes IO Summary/IO Lists/IO Schedule.', NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 233),
('4380', 'Other List', NULL, NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 234),
('4880', 'Other Manual', 'A document that describes methods of working to be used to accomplish an activity. Synonym: Guide, Guideline. Warning: Not to replace "Books", as defined in the EIS Section 3.4 which requires an Index to be created. See Index of Documents.', NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 235),
('5180', 'Other Design', NULL, NULL, NULL, 'IN', 'Instrumentation', 'IFI, AFU, AFP, AFT', true, 236),
