('3366', 'Technical Query', 'Technical Query  Includes STQ (Site Technical Query)', NULL, NULL, 'E02', 'Electrical Power', 'IFI, AFU, AFP, AFT', true, 909),
('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.   Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 910),
('4027', 'Schematic Diagram', 'A simplified representation of a control system(s) showing the main connections between the field signals and the control system devices. Usually includes a high-level summary of the control system hardware, such as the types and quantity of controllers and I/O items. Single Line Diagrams (SLD), Utility Flow Diagrams (UFD), Three Line Diagrams (TLD), Protective Device Coordination Diagrams (PDCD). Includes SLDs for Electrical Substations.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 911),
('4030', 'Wiring Diagram', 'Shows the connections of an installation or its component devices or parts. It may cover internal or external connections or both, and contains such detail as is needed to make or trace connections that are involved.  Includes: Wiring Diagram, Cable Block Diagram, Cable Interconnection Diagram, Cable Schedule, Block Diagram, Electrical Wiring Interconnection Drawing, Panel / Kiosk Internal Wiring Drawing.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 912),
('4033', 'Routing Drawing', 'Cable tray / duct / trench routing and support arrangement drawing.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 913),
('4036', 'Classification Drawing', 'Hazardous Area Classification Drawing showing the location and extent of each classified area, inclusive of Area Classification schedules. Includes Zone Plans.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 914),
('4039', 'Lighting Layout Drawing', 'Shows the positions, circuitry and details of lighting (general, emergency, navigational, etc.) and small power (socket outlets) in an area.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 915),
('4042', 'Earthing Drawing', 'Earthing/Grounding drawings show the earth/ground protection system for the facility, including location and route of earth conductors and earth electrodes.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 916),
('4080', 'Other Drawing', NULL, 'Tier 1', 'RLMU', 'E02', 'Electrical Power', 'ASB, AFC, AFU, AFD', true, 917),
('4301', 'Action List', 'Includes Punch List.', NULL, NULL, 'E02', 'Electrical Power', 'IFI, AFU, AFP, AFT', true, 918),
('4309', 'Cable Schedule', 'A schedule / list of cables, usually identified by a unique cable number plus details (type, cores, rating, routing etc).', NULL, NULL, 'E02', 'Electrical Power', 'IFI, AFU, AFP, AFT', true, 919),
('4312', 'Consumer Load List', 'A listing of each significant consumer/load item with key power supply information. It includes voltage, starting and running current, protection device ratings. It may include characteristics of the power system. A Load List feeds directly into a system Load Flow Study.', NULL, NULL, 'E02', 'Electrical Power', 'IFI, AFU, AFP, AFT', true, 920),
('4380', 'Other List', NULL, NULL, NULL, 'E02', 'Electrical Power', 'IFI, AFU, AFP, AFT', true, 921),
