('3311', 'Change Notification', 'An advance notice to another party, e.g. another design department or fabrication facility, that there is going to be a change to a document that has been issued for construction. Synonyms include DCN Design Change Notice, ACN Advanced Change Notice.', NULL, NULL, 'I03', 'Fire and Gas Detection', 'IFI, AFU, AFP, AFT', true, 971),
('3322', 'Demonstration Note On Compliance', 'A document that demonstrates that the design meets the Process Safety Basic Requirements (PSBR) of DEM 2 with evidences and references to documents.', NULL, NULL, 'I03', 'Fire and Gas Detection', 'IFI, AFU, AFP, AFT', true, 972),
('3366', 'Technical Query', 'Technical Query  Includes STQ (Site Technical Query)', NULL, NULL, 'I03', 'Fire and Gas Detection', 'IFI, AFU, AFP, AFT', true, 973),
('4045', 'Block Diagram', 'A simplified representation of a control system(s) showing the main connections between the field signals and the control system devices. Usually includes a high-level summary of the control system hardware, such as the types and quantity of controllers and I/O items.', 'Tier 1', 'RLMU', 'I03', 'Fire and Gas Detection', 'ASB, AFC, AFU, AFD', true, 974),
('4048', 'Cause and Effect Diagram', 'A chart or matrix with logic representation of the relationship between a field condition (cause) and the results of that condition (effects) within a control system. It links measurements, alarms, trips and corresponding actions.  Does not include Fishbone cause and effect (a.k.a. Ishikawa Diagram) used for Root Cause Analysis or HAZOP study techniques. Includes Process Safety Logic Charts (PSLC).', 'Tier 1', 'RLMU', 'I03', 'Fire and Gas Detection', 'ASB, AFC, AFU, AFD', true, 975),
('4051', 'Instrument Hook-Up Drawing', 'A drawing showing the details of a typical installation of a group of instruments or a single instrument. These are typically arranged in a book or manual.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'I03', 'Fire and Gas Detection', 'ASB, AFC, AFU, AFD', true, 976),
('4054', 'Instrument Location Drawing', 'A 2D plan view of a process area showing the location and identification of instruments, including junction boxes, marshalling cabinets, control rooms and equipment rooms.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'I03', 'Fire and Gas Detection', 'ASB, AFC, AFU, AFD', true, 977),
('4057', 'Instrument Loop Drawing', 'A diagram showing a control loop (or multiple loops) including connections, signal types and ranges, cables, junction boxes, terminations and configuration of the instruments and devices within each loop.', 'Tier 1', 'RLMU', 'I03', 'Fire and Gas Detection', 'ASB, AFC, AFU, AFD', true, 978),
