('4322', 'Equipment Summary List', 'An extract from a Register (see 6612 Equipment Register) that is used as a secondary reference (ie. not the master).', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1059),
('4380', 'Other List', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1060),
('4880', 'Other Manual', 'A document that describes methods of working to be used to accomplish an activity. Synonym: Guide, Guideline. Warning: Not to replace "Books", as defined in the EIS Section 3.4 which requires an Index to be created. See Index of Documents.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1061),
('5180', 'Other Design', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1062),
('5206', 'Other Picture', 'Photo or Illustration', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1063),
('5503', 'Design Basis', 'Overall design basis and criteria for a project is called Design Basis Memorandum, whereas the one defined for a specific (sub)-discipline is the Discipline Design Basis. Synonyms: Design Criteria, Design Basis Memorandum, Discipline Design Basis, Design Basis of Estimate (DBOE), Basis of Design (BOD), Discipline Design Criteria, Process Design Basis.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1064),
('5529', 'Project Philosophy', 'Including buildings, access, drainage, corrosion/materials, electrical design, fire and gas, commissioning, isolation, maintenance, operations (inc. start-up/shutdown), earthing, HVAC, metering, process control, well control,  utility requirements and design.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1065),
('5798', 'Project Plan', 'Reserved for project wide Discipline Management Plans such as Project QA Plan, Project HSES Plan, Project IM Plan, etc... For Discipline AA only, this doc type is used to classify Project Implementation Plan (PIP) and Project Execution Plan (PEP).', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1066),
('5880', 'Other Plan', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1067),
('6080', 'Other Procedure', 'For Project Procedures Manual use AA5798, unless project wishes to register separate documents for individual procedures within a Project Procedures Manual.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1068),
('6612', 'Equipment Register', 'A register/database containing all pertinent data about equipment that is installed on the facility. Frequently referred to as the CMMS (Computerised Maintenance Management System). Refer to the EPC/IM Contract Scope of Work (the EXHIBIT-G, section 5.3 / 5.4 / 5.5 for more detail). Includes Equipment Database, Summary Equipment Database, Approved Equipment List etc.  For Project Material Master data list use doc type 6680.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1069),
('6680', 'Other Register', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1070),
('7080', 'Other Report', 'Including: Summary Report, Final Report, Assessment Report, Evaluation Report, Commissioning Report, Completion Report, Asset Report, Performance Report.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1071),
('7416', 'Other Assurance Review Report', 'Provides an independent assurance that project schedules, cost estimates, technical design, competence, etc. accurately represent the project scope, the risks to project delivery, and are compliant with Group project guides and standards. Usually used as input to a Value Assurance Review VAR. Includes Estimate and Schedule Assurance Review (ESAR) under FA, and Technical Assurance Reviews under AA for multidiscipline reviews, or individual disciplines for specific reviews.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1072),
('7480', 'Other Review Report', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1073),
('7739', 'Project Specification', 'A technical description of the information on a Project necessary to prepare a +/-10% estimate, including references to:  - technical specifications required to prepare detailed design and engineering work  - procedures and requirements for the execution of the work and services for the realisation of a project Note: This doc type is not a BOOK as defined in the EIS. It is a document referencing other specifications, procedures, etc.', NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1074),
('7780', 'Other Specification', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1075),
('8109', 'Process Simulation', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1076),
('8180', 'Other Calculation', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1077),
('8280', 'Other Schedule', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1078),
('8380', 'Other Study', NULL, NULL, NULL, 'P02', 'Flow Assurance', 'IFI, AFU, AFP, AFT', true, 1079),
('0480', 'Other Agreement', 'Other Agreement', NULL, NULL, 'L02', 'Piping Materials', 'IFI., AFU, AFP, AFT', true, 1080),
('3311', 'Change Notification', 'An advance notice to another party, e.g. another design department or fabrication facility, that there is going to be a change to a document that has been issued for construction. Synonyms include DCN Design Change Notice, ACN Advanced Change Notice.', NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1081),
('3322', 'Demonstration Note On Compliance', 'A document that demonstrates that the design meets the Process Safety Basic Requirements (PSBR) of DEM 2 with evidences and references to documents.', NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1082),
('3366', 'Technical Query', 'Technical Query  Includes STQ (Site Technical Query)', NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1083),
('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.   Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'L02', 'Piping Materials', 'ASB, AFC, AFU, AFD', true, 1084),
('4069', 'Isometric Drawing', 'A 3D dimensional representation of piping. Shows relevant piping data such as materials, wall thickness, weld details and positions, elevation heights, etc. May show stress points. 3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'L02', 'Piping Materials', 'ASB, AFC, AFU, AFD', true, 1085),
('4072', 'Piping Arrangement Drawing', 'A piping drawing, usually in plan/elevation format, showing the routing and physical arrangement of pipes within a given area/building. Shows relevant piping data such as materials, wall thickness, connection details, support locations, etc.  3D information may be extracted and issued in 2D format as a document or may alternatively be extracted from the 3D model directly by the viewer.', 'Tier 1', 'RLMU', 'L02', 'Piping Materials', 'ASB, AFC, AFU, AFD', true, 1086),
('4075', 'Process and Instrumentation Diagram', 'PandID - A diagram that shows all the relevant process and control information for each system using symbols and lines to represent equipment, piping, instrumentation, control devices, control philosophy/strategy and significant services. It is considered to be the master document to be used during Construction and Operation.', 'Tier 1', 'RLMU', 'L02', 'Piping Materials', 'ASB, AFC, AFU, AFD', true, 1087),
('4078', 'Process Flow Diagram', 'PFD - A diagram used to define the process for a facility. There are many process/piping parameters listed on the PFD such as process flows, compositions, pressures and temperatures for each significant process and utility stream and for each operating case. Also called: Heat and Material Balance (H and MB, HMB), Process Scheme (PS).', 'Tier 1', 'RLMU', 'L02', 'Piping Materials', 'ASB, AFC, AFU, AFD', true, 1088),
('4080', 'Other Drawing', NULL, 'Tier 1', 'RLMU', 'L02', 'Piping Materials', 'ASB, AFC, AFU, AFD', true, 1089),
('4301', 'Action List', 'Includes Punch List.', NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1090),
('4324', 'Line List', 'A tabulation listing all (piping) lines within a project scope, with corresponding characteristics (sizes, materials, design data, insulation requirements, test requirements, etc).', NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1091),
('4327', 'Valve Summary List', 'A tabulation listing the main data (e.g. types, pressure ratings, end connections, trim requirements, operators, accessories, etc.) applicable to each (piping) valve within the project scope, usually on a one line per item basis. Sometimes a valve is so important it needs a separate specification.', NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1092),
('4380', 'Other List', NULL, NULL, NULL, 'L02', 'Piping Materials', 'IFI, AFU, AFP, AFT', true, 1093),
