('8203', 'HAZOP / HAZID', 'The objective of a HAZOP study is to identify safety hazards and operability issues of a facility design or a process. Uses a creative, systematic approach to examine the design.  This item includes both HAZID and HAZOP studies.', NULL, NULL, 'H02', 'Process Safety', 'IFI, AFU, AFP, AFT', true, 1131),
('8206', 'Environmental Impact Assessment', 'A report on the results of a study of the environmental impacts attributable to the project, used as a basis of decision-making, and which includes a description of proposed measures to mitigate the impacts.', NULL, NULL, 'H02', 'Process Safety', 'IFI, AFU, AFP, AFT', true, 1132),
('8209', 'Fire Risk Assessment', 'Fire and Explosion Hazard Analysis (FEHA), Fire Hazard Assessment (FHA), Fire and Blast Assessment (FBA).', NULL, NULL, 'H02', 'Process Safety', 'IFI, AFU, AFP, AFT', true, 1133),
