('4018', 'General Arrangement Diagram', 'A diagram showing the main features and locations of major items. Usually has some dimensions to convey spatial relationships but is generally inadequate for construction.   Architectural: Sometimes includes layouts of all rooms including equipment and accommodation, external layouts and elevations.', 'Tier 1', 'RLMU', 'H04', 'Fire Protection', 'ASB, AFC, AFU, AFD', true, 1172),
('4080', 'Other Drawing', NULL, 'Tier 1', 'RLMU', 'H04', 'Fire Protection', 'ASB, AFC, AFU, AFD', true, 1173),
('4301', 'Action List', 'Includes Punch List.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1174),
('4380', 'Other List', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1175),
('4880', 'Other Manual', 'A document that describes methods of working to be used to accomplish an activity. Synonym: Guide, Guideline. Warning: Not to replace "Books", as defined in the EIS Section 3.4 which requires an Index to be created. See Index of Documents.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1176),
('5180', 'Other Design', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1177),
('5529', 'Project Philosophy', 'Including buildings, access, drainage, corrosion/materials, electrical design, fire and gas, commissioning, isolation, maintenance, operations (inc. start-up/shutdown), earthing, HVAC, metering, process control, well control,  utility requirements and design.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1178),
('5798', 'Project Plan', 'Reserved for project wide Discipline Management Plans such as Project QA Plan, Project HSES Plan, Project IM Plan, etc... For Discipline AA only, this doc type is used to classify Project Implementation Plan (PIP) and Project Execution Plan (PEP).', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1179),
('5880', 'Other Plan', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1180),
('6080', 'Other Procedure', 'For Project Procedures Manual use AA5798, unless project wishes to register separate documents for individual procedures within a Project Procedures Manual.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1181),
('6680', 'Other Register', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1182),
('7080', 'Other Report', 'Including: Summary Report, Final Report, Assessment Report, Evaluation Report, Commissioning Report, Completion Report, Asset Report, Performance Report.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1183),
('7416', 'Other Assurance Review Report', 'Provides an independent assurance that project schedules, cost estimates, technical design, competence, etc. accurately represent the project scope, the risks to project delivery, and are compliant with Group project guides and standards. Usually used as input to a Value Assurance Review VAR. Includes Estimate and Schedule Assurance Review (ESAR) under FA, and Technical Assurance Reviews under AA for multidiscipline reviews, or individual disciplines for specific reviews.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1184),
('7480', 'Other Review Report', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1185),
('7739', 'Project Specification', 'A technical description of the information on a Project necessary to prepare a +/-10% estimate, including references to:  - technical specifications required to prepare detailed design and engineering work  - procedures and requirements for the execution of the work and services for the realisation of a project Note: This doc type is not a BOOK as defined in the EIS. It is a document referencing other specifications, procedures, etc.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1186),
('7780', 'Other Specification', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1187),
('8180', 'Other Calculation', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1188),
('8203', 'HAZOP / HAZID', 'The objective of a HAZOP study is to identify safety hazards and operability issues of a facility design or a process. Uses a creative, systematic approach to examine the design.  This item includes both HAZID and HAZOP studies.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1189),
('8206', 'Environmental Impact Assessment', 'A report on the results of a study of the environmental impacts attributable to the project, used as a basis of decision-making, and which includes a description of proposed measures to mitigate the impacts.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1190),
('8209', 'Fire Risk Assessment', 'Fire and Explosion Hazard Analysis (FEHA), Fire Hazard Assessment (FHA), Fire and Blast Assessment (FBA).', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1191),
('8212', 'Quantitative Risk Assessment', 'Quantitative Risk Assessment. Also Concept Risk Assessment (CRA) and Concept Safety Assessment (CSA). Note: For use in HSE&S discipline only', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1192),
('8215', 'Safety Case', 'A document produced by the operator describing the SMS. This requires the formal identification of the hazards and risks; the measures taken to reduce the identified risks to a level that is As Low As Reasonably Practicable; and the Safety Management System to ensure the implementation and compliance of risk reduction measures.', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1193),
('8218', 'SIL Study', 'Safety integrity Level study', NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1194),
('8280', 'Other Schedule', NULL, NULL, NULL, 'H04', 'Fire Protection', 'IFI, AFU, AFP, AFT', true, 1195),
