('0480', 'Other Agreement', 'Other Agreement', NULL, NULL, 'FA', 'Cost and Planning', 'IFI., AFU, AFP, AFT', true, 1197),
('3003', 'Cost Estimate Report', 'See also XA/FA 3180 for "Other Estimates" including Estimate Supplements. The Cost Estimate Report is an estimate of the total cost associated with the entire scope of work as defined in the Project Execution Plan at the date of the estimate. It is compiled, as a minimum, by the cost structure for the project, for each phase and includes all expenditure to completion, Sunk Cost and Actual.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1198),
('3180', 'Other Estimate', NULL, NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1199),
('3311', 'Change Notification', 'An advance notice to another party, e.g. another design department or fabrication facility, that there is going to be a change to a document that has been issued for construction. Synonyms include DCN Design Change Notice, ACN Advanced Change Notice.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1200),
