('7001', 'Audit Report', 'An authoritative evaluation of the quality, performance, system(s) or processes of a given body in a given discipline. Usually done by a qualified auditor.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1214),
('7003', 'Monthly Progress Report', 'Provides overall project health status against agreed baselines and targets to stakeholders. It typically captures: scope changes, engineering progress, schedule performance, resource/cost performance, financial/commercial status, risk items, procurement/supplier status, quality and HSE performance, outstanding issues/actions, and decisions/approvals required. Often includes dashboards, KPIs, and trend charts.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1215),
('7006', 'Stage Gate Report', 'End of Phase deliverable summarizing phase accomplishments, technical definitions, risks/uncertainties, compliance with Company standards/regulations, project readiness and team recommendations.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1216),
('7080', 'Other Report', 'Including: Summary Report, Final Report, Assessment Report, Evaluation Report, Commissioning Report, Completion Report, Asset Report, Performance Report.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1217),
('7406', 'Value Assurance Review Report', 'Assessment report of the project team, their work and the deliverables so far to reach a gate decision. The VAR is a mandatory cross-functional review of the project, involving all relevant disciplines. It covers the full scope of the project and assesses the maturity of the development and especially the feasibility of the proposed concept and plan. Includes any Independent Peer Review Report.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1218),
('7416', 'Other Assurance Review Report', 'Provides an independent assurance that project schedules, cost estimates, technical design, competence, etc. accurately represent the project scope, the risks to project delivery, and are compliant with Group project guides and standards. Usually used as input to a Value Assurance Review VAR. Includes Estimate and Schedule Assurance Review (ESAR) under FA, and Technical Assurance Reviews under AA for multidiscipline reviews, or individual disciplines for specific reviews.', NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1219),
('7480', 'Other Review Report', NULL, NULL, NULL, 'FA', 'Cost and Planning', 'IFI, AFU, AFP, AFT', true, 1220),
